--- mobile/app/(tabs)/_layout.tsx ---
import { BlurView } from "expo-blur";
import { Tabs } from "expo-router";
import { Feather } from "@expo/vector-icons";
import React from "react";
import { Platform, StyleSheet, Text, View, useColorScheme } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";

import { useColors } from "@/hooks/useColors";

export default function TabLayout() {
  const colors = useColors();
  const colorScheme = useColorScheme();
  const isDark = colorScheme === "dark";
  const isIOS = Platform.OS === "ios";
  const isWeb = Platform.OS === "web";
  const insets = useSafeAreaInsets();

  const TAB_HEIGHT = isWeb ? 62 : 60;
  const bottomSafe = isWeb ? 0 : Math.max(insets.bottom, 16);
  const tabBarHeight = TAB_HEIGHT + bottomSafe;

  const TabIcon = ({
    name,
    label,
    color,
    focused,
  }: {
    name: React.ComponentProps<typeof Feather>["name"];
    label: string;
    color: string;
    focused: boolean;
  }) => (
    <View style={[styles.tabItem, focused && { backgroundColor: color + "18" }]}>
      <Feather name={name} size={18} color={color} />
      <Text style={[styles.tabLabel, { color }]}>{label}</Text>
    </View>
  );

  return (
    <Tabs
      screenOptions={{
        tabBarActiveTintColor: colors.primary,
        tabBarInactiveTintColor: colors.mutedForeground + "99",
        headerShown: false,
        tabBarShowLabel: false,
        tabBarStyle: {
          position: "absolute",
          backgroundColor: isIOS ? "transparent" : colors.card + "f5",
          borderTopWidth: StyleSheet.hairlineWidth,
          borderTopColor: colors.border,
          elevation: 0,
          height: tabBarHeight,
          paddingBottom: bottomSafe,
          paddingTop: 4,
        },
        tabBarBackground: () =>
          isIOS ? (
            <BlurView
              intensity={90}
              tint={isDark ? "dark" : "dark"}
              style={StyleSheet.absoluteFill}
            />
          ) : (
            <View style={[StyleSheet.absoluteFill, { backgroundColor: colors.card + "f5" }]} />
          ),
        tabBarIconStyle: { marginBottom: 0 },
      }}
    >
      <Tabs.Screen
        name="index"
        options={{
          title: "Projetos",
          tabBarIcon: ({ color, focused }) => (
            <TabIcon name="folder" label="Projetos" color={color} focused={focused} />
          ),
        }}
      />
      <Tabs.Screen
        name="editor"
        options={{
          title: "Editor",
          tabBarIcon: ({ color, focused }) => (
            <TabIcon name="code" label="Editor" color={color} focused={focused} />
          ),
        }}
      />
      <Tabs.Screen
        name="terminal"
        options={{
          title: "Terminal",
          tabBarIcon: ({ color, focused }) => (
            <TabIcon name="terminal" label="Terminal" color={color} focused={focused} />
          ),
        }}
      />
      <Tabs.Screen
        name="tasks"
        options={{
          title: "Tarefas",
          tabBarIcon: ({ color, focused }) => (
            <TabIcon name="check-square" label="Tarefas" color={color} focused={focused} />
          ),
        }}
      />
      <Tabs.Screen
        name="plugins"
        options={{
          title: "Plugins",
          tabBarIcon: ({ color, focused }) => (
            <TabIcon name="package" label="Plugins" color={color} focused={focused} />
          ),
        }}
      />
      <Tabs.Screen
        name="ai"
        options={{
          title: "IA",
          tabBarIcon: ({ color, focused }) => (
            <TabIcon name="cpu" label="IA" color={color} focused={focused} />
          ),
        }}
      />
      <Tabs.Screen
        name="settings"
        options={{
          title: "Config",
          tabBarIcon: ({ color, focused }) => (
            <TabIcon name="settings" label="Config" color={color} focused={focused} />
          ),
        }}
      />
    </Tabs>
  );
}

const styles = StyleSheet.create({
  tabItem: {
    alignItems: "center",
    justifyContent: "center",
    paddingHorizontal: 6,
    paddingVertical: 4,
    borderRadius: 8,
    gap: 2,
    minWidth: 44,
  },
  tabLabel: {
    fontSize: 9,
    fontWeight: "600",
    letterSpacing: 0.2,
  },
});

--- mobile/app/(tabs)/ai.tsx ---
import { Feather } from "@expo/vector-icons";
import React, { useState } from "react";
import { Platform, StyleSheet, Text, TouchableOpacity, View } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";

import AIChat from "@/components/AIChat";
import VoiceAssistant from "@/components/VoiceAssistant";
import { useColors } from "@/hooks/useColors";
import { useApp } from "@/context/AppContext";

export default function AIScreen() {
  const colors = useColors();
  const insets = useSafeAreaInsets();
  const topPadding = Platform.OS === "web" ? 14 : insets.top;
  const tabBottom = Platform.OS === "web" ? 70 : Math.max(insets.bottom, 16) + 70;
  const [voiceOpen, setVoiceOpen] = useState(false);
  const { getActiveAIProvider } = useApp();
  const provider = getActiveAIProvider();

  return (
    <View style={[styles.container, { backgroundColor: colors.background, paddingBottom: tabBottom }]}>
      <View
        style={[
          styles.header,
          {
            paddingTop: topPadding + 6,
            backgroundColor: colors.card,
            borderBottomColor: colors.border,
          },
        ]}
      >
        <View style={styles.headerLeft}>
          <Text style={[styles.headerTitle, { color: colors.foreground }]}>Assistente IA</Text>
          <View style={{ flexDirection: "row", alignItems: "center", gap: 6, marginTop: 2 }}>
            <View style={{ width: 7, height: 7, borderRadius: 4, backgroundColor: provider ? "#22c55e" : "#ef4444" }} />
            <Text style={[styles.headerSub, { color: provider ? "#22c55e" : colors.mutedForeground }]}>
              {provider ? provider.name : "Nenhum provedor — vá em Config"}
            </Text>
          </View>
        </View>
        <TouchableOpacity
          onPress={() => setVoiceOpen(true)}
          style={[styles.voiceBtn, { backgroundColor: "#6366f1" }]}
          accessibilityLabel="Conversa por voz"
        >
          <Feather name="radio" size={16} color="#fff" />
          <Text style={styles.voiceBtnText}>🎙️ Voz</Text>
        </TouchableOpacity>
      </View>

      <AIChat />

      <VoiceAssistant visible={voiceOpen} onClose={() => setVoiceOpen(false)} />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    paddingHorizontal: 16,
    paddingBottom: 10,
    borderBottomWidth: 1,
  },
  headerLeft: { flex: 1, gap: 2 },
  headerTitle: { fontSize: 16, fontWeight: "700" },
  headerSub: { fontSize: 12 },
  voiceBtn: {
    flexDirection: "row",
    alignItems: "center",
    gap: 6,
    paddingHorizontal: 14,
    paddingVertical: 8,
    borderRadius: 20,
  },
  voiceBtnText: { color: "#fff", fontSize: 13, fontWeight: "600" },
});

