  }

  listar(filtro = {}) {
    return this.dados.filter(d =>
      Object.entries(filtro).every(([k, v]) => d[k] === v)
    );
  }

  remover(id) {
    const idx = this.dados.findIndex(d => d.id === id);
    if (idx === -1) return false;
    this.dados.splice(idx, 1);
