        ]}
      >
        <View style={{ flex: 1 }}>
          <Text style={[styles.headerTitle, { color: colors.foreground }]}>Taski</Text>
          <Text style={[styles.headerSub, { color: colors.mutedForeground }]}>
            {activeProject ? activeProject.name : "Nenhum projeto ativo"}
          </Text>
